class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[-1] = 1
        for i in range(n - 1, -1, -1):
            if s[i] == '0':
                continue
            for j in range(i, n):
                num = int(s[i:j+1])
                if 1 <= num <= k:
                    dp[i] = (dp[i] + dp[j+1]) % MOD
        return dp[0]

